import sys
from collections import Counter

def is_good_string(s):
    freq = Counter(s)
    count_by_freq = Counter(freq.values())

    for i in range(1, max(freq.values()) + 1):
        cnt = count_by_freq.get(i, 0)
        if cnt != 0 and cnt != 2:
            return False
    return True

def main():
    s = sys.stdin.readline().strip()
    if is_good_string(s):
        print("Yes")
    else:
        print("No")

if __name__ == "__main__":
    main()
